import{_ as a,o as t,c as r,a0 as l}from"./chunks/framework.D7jNN1Sc.js";const m=JSON.parse('{"title":"MA Material Helper","description":"","frontmatter":{},"headers":[],"relativePath":"en/features/ma-material-helper.md","filePath":"en/features/ma-material-helper.md"}'),o={name:"en/features/ma-material-helper.md"};function s(i,e,n,d,c,p){return t(),r("div",null,[...e[0]||(e[0]=[l(`<h1 id="ma-material-helper" tabindex="-1">MA Material Helper <a class="header-anchor" href="#ma-material-helper" aria-label="Permalink to &quot;MA Material Helper&quot;">​</a></h1><p>Automatically generates color change menus using Modular Avatar&#39;s material control components. Create color change menus from color variation prefabs in just a few clicks, with support for simultaneous generation from multiple prefabs.</p><p><strong>Requirement:</strong> <a href="https://modular-avatar.nadena.dev/" target="_blank" rel="noreferrer">Modular Avatar</a> 1.13.0 or higher</p><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><ol><li>Select color variation prefabs → Right-click → <code>Copy Material Setup</code> (multiple selection supported)</li><li>Select target outfit → Right-click → Choose one of the following:</li></ol><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>Create Material Setter</code></td><td>Set materials per slot (<strong>recommended</strong>)</td></tr><tr><td><code>[Optional] Create Material Setter (All Slots)</code></td><td>Create setters for all slots (for manual customization)</td></tr><tr><td><code>Create Material Swap</code></td><td>Set materials by replacement rules</td></tr><tr><td><code>[Optional] Create Material Swap (Per Object)</code></td><td>Create individual swaps per object</td></tr></tbody></table><p>A &quot;Color Menu&quot; with numbered color variations (Color1, Color2, etc.) is automatically created.</p><h2 id="material-setter-vs-material-swap" tabindex="-1">Material Setter vs Material Swap <a class="header-anchor" href="#material-setter-vs-material-swap" aria-label="Permalink to &quot;Material Setter vs Material Swap&quot;">​</a></h2><p><strong>Material Setter is recommended for most use cases.</strong></p><table tabindex="0"><thead><tr><th></th><th>Material Setter</th><th>Material Swap</th></tr></thead><tbody><tr><td>Assignment unit</td><td>Per slot</td><td>Per material name</td></tr><tr><td>Same material → different targets in one mesh</td><td>Supported</td><td>Not supported</td></tr><tr><td>Use case</td><td>Most cases</td><td>Simple configurations</td></tr></tbody></table><h3 id="cases-material-swap-cannot-handle" tabindex="-1">Cases Material Swap Cannot Handle <a class="header-anchor" href="#cases-material-swap-cannot-handle" aria-label="Permalink to &quot;Cases Material Swap Cannot Handle&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Mesh A:</span></span>
<span class="line"><span>  Slot 0: Material X → want to change to Material Y</span></span>
<span class="line"><span>  Slot 1: Material X → want to change to Material Z</span></span></code></pre></div><p>Material Swap can only replace &quot;Material X&quot; with one material, so both slots end up with the same result. Material Setter can specify per slot, allowing each to change to a different material.</p><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>Right-click in Hierarchy → <code>Kanameliser Editor Plus &gt; Copy Material Setup / Create Material Setter / Create Material Swap</code></p>`,15)])])}const u=a(o,[["render",s]]);export{m as __pageData,u as default};
